#include <iostream>
#include <string>
#include <limits>
using namespace std;

double calculate(double a, double b, string op)
{
    if (op == "+") return a + b;
    if (op == "-") return a - b;
    if (op == "*") return a * b;
    if (op == "/")
    {
        if (b == 0)
        {
            cout << "Hata: Sifira bolme!" << endl;
            return numeric_limits<double>::quiet_NaN();
        }
        return a / b;
    }
    cout << "Gecersiz islem: " << op << endl;
    return numeric_limits<double>::quiet_NaN();
}

int main()
{
    double x = 15, y = 4;

    cout << "x = " << x << ", y = " << y << endl;
    cout << "x + y = " << calculate(x, y, "+") << endl;
    cout << "x - y = " << calculate(x, y, "-") << endl;
    cout << "x * y = " << calculate(x, y, "*") << endl;
    cout << "x / y = " << calculate(x, y, "/") << endl;

    cout << "\nSifira bolme testi:" << endl;
    calculate(10, 0, "/");

    // Yuzde hesaplama
    double total = 250, discount = 15;
    double finalPrice = total - (total * discount / 100);
    cout << "\n" << total << " TL'nin %" << discount << " indirimli hali: " << finalPrice << " TL" << endl;

    return 0;
}
